import{_ as e,c as a,o as s,a1 as n}from"./chunks/framework.DDNAyvCW.js";const h=JSON.parse('{"title":"Privacy Settings","description":"","frontmatter":{},"headers":[],"relativePath":"docs/privacy/settings/index.md","filePath":"docs/privacy/settings/index.md"}'),i={name:"docs/privacy/settings/index.md"};function r(o,t,d,c,l,p){return s(),a("div",null,t[0]||(t[0]=[n('<h1 id="privacy-settings" tabindex="-1">Privacy Settings <a class="header-anchor" href="#privacy-settings" aria-label="Permalink to &quot;Privacy Settings&quot;">​</a></h1><p>Control what data Chaterm collects, how sensitive information is handled, and whether your settings sync across devices.</p><p>For details on exactly what is tracked and why, see the <a href="/docs/privacy/policy/">Privacy Policy</a>.</p><h2 id="telemetry" tabindex="-1">Telemetry <a class="header-anchor" href="#telemetry" aria-label="Permalink to &quot;Telemetry&quot;">​</a></h2><p>Telemetry sends anonymous usage data and error reports to help improve Chaterm. No code, prompts, or conversation content is ever collected.</p><table tabindex="0"><thead><tr><th>Data category</th><th>What is included</th></tr></thead><tbody><tr><td>Task interactions</td><td>Start/end times, conversation flow (without content)</td></tr><tr><td>Mode and tool usage</td><td>AI modes selected, tools invoked</td></tr><tr><td>Token usage</td><td>Conversation-length metrics for cost estimation</td></tr><tr><td>UI activity</td><td>Feature usage across the interface</td></tr><tr><td>Error reports</td><td>Anonymized error information</td></tr></tbody></table><p><strong>Toggle</strong>: Settings &gt; Privacy &gt; Telemetry -- <strong>Enable</strong> or <strong>Disable</strong>.</p><div class="tip custom-block"><p class="custom-block-title">Recommendation</p><p>Enabling telemetry helps the Chaterm team prioritize features and fix issues faster. All data is anonymized and never reveals private information.</p></div><h2 id="sensitive-data-masking" tabindex="-1">Sensitive Data Masking <a class="header-anchor" href="#sensitive-data-masking" aria-label="Permalink to &quot;Sensitive Data Masking&quot;">​</a></h2><p>Sensitive data masking automatically obscures passwords, keys, tokens, and other secrets in AI dialog outputs.</p><p><strong>What it does</strong>:</p><ul><li>Identifies common sensitive patterns in real time</li><li>Masks matching content before it appears on screen</li><li>Works without affecting normal usage</li></ul><p><strong>When to use it</strong>:</p><ul><li>Sharing your screen or recording a session</li><li>Working in a public environment</li><li>Reviewing AI output that may reference credentials</li></ul><p><strong>Toggle</strong>: Settings &gt; Privacy &gt; Sensitive Data Masking -- <strong>Enable</strong> or <strong>Disable</strong>.</p><div class="warning custom-block"><p class="custom-block-title">Limitation</p><p>Masking covers common sensitive patterns but cannot guarantee 100% detection. Exercise caution when handling highly sensitive information.</p></div><h2 id="data-sync" tabindex="-1">Data Sync <a class="header-anchor" href="#data-sync" aria-label="Permalink to &quot;Data Sync&quot;">​</a></h2><p>Data sync keeps your configurations, assets, and keys consistent across every device where you use Chaterm.</p><p><strong>What is synced</strong>:</p><table tabindex="0"><thead><tr><th>Data type</th><th>Examples</th></tr></thead><tbody><tr><td>Assets</td><td>Host connection details, SSH keys</td></tr><tr><td>Credentials</td><td>Saved passwords and tokens</td></tr><tr><td>AI Historical Conversation</td><td>Record of Historical AI Conversations</td></tr></tbody></table><p>All synced data is encrypted with KMS during transmission and storage.</p><p><strong>Toggle</strong>: Settings &gt; Privacy &gt; Data Sync -- <strong>Enable</strong> or <strong>Disable</strong>.</p><div class="warning custom-block"><p class="custom-block-title">Cloud Storage</p><p>When data sync is enabled, your configuration data is stored in the cloud. Make sure you trust Chaterm&#39;s security measures before enabling this feature for sensitive environments.</p></div><div class="tip custom-block"><p class="custom-block-title">Recommendation</p><p>If you use Chaterm on multiple devices, enabling data sync avoids repeated setup and provides a consistent experience.</p></div><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><p><strong>Data minimization</strong> -- Enable only the features you need and review your privacy settings periodically.</p><p><strong>Sensitive information</strong> -- Keep masking enabled when presenting or recording. Avoid pasting raw secrets into conversations; use environment variables or a secrets manager instead.</p><p><strong>Multi-device usage</strong> -- Clear local data after using Chaterm on a shared or public device. Review synced data regularly.</p>',28)]))}const u=e(i,[["render",r]]);export{h as __pageData,u as default};
